function addListItem(t,e){const s=document.createElement("li");s.classList.add("list-group-item"),s.classList.add("d-flex"),s.classList.add("justify-content-between"),s.innerHTML=`\n                    <span>${t}</span>\n                    <button type="button" class="btn btn-danger btn-sm">Удалить</button>\n                `,e.appendChild(s)}setTimeout(()=>{const t=document.querySelector("#contentInput"),e=document.querySelector("#list");let s=[];chrome.storage.local.get("list",t=>{t.list?(s=t.list).forEach(t=>{addListItem(t,e)}):chrome.storage.local.set({list:s})}),document.addEventListener("click",t=>{if("BUTTON"===t.target.tagName){const e=t.target.closest("li"),n=e.querySelector("span").textContent.trim(),a=s.findIndex(t=>t===n);a>=0&&(s.splice(a,1),chrome.storage.local.set({list:s}),e.remove())}}),t.addEventListener("keydown",n=>{"Enter"===n.key&&(s.push(n.target.value),chrome.storage.local.set({list:s}),addListItem(n.target.value,e),t.value="")})});
